#include <iostream>
#include <vector>
#include <algorithm>
#include <cstring>
using namespace std;

const int maxn = 200010;

vector<int> g[maxn];
int n, a, b;
int dfn[maxn], low[maxn], timer;
bool cut[maxn];

void tarjan(int u) {
    dfn[u] = low[u] = ++timer;
    for (int v : g[u]) {
        if (!dfn[v]) {
            tarjan(v);
            low[u] = min(low[u], low[v]);
            if (low[v] >= dfn[u] && u != a && dfn[b] >= dfn[v]) {
                cut[u] = true;
            }
        } else {
            low[u] = min(low[u], dfn[v]);
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    memset(dfn, 0, sizeof(dfn));
    memset(low, 0, sizeof(low));
    memset(cut, false, sizeof(cut));

    cin >> n;
    int u, v;
    while (cin >> u >> v && !(u == 0 && v == 0)) {
        g[u].push_back(v);
        g[v].push_back(u);
    }
    cin >> a >> b;

    tarjan(a);

    for (int i = 1; i <= n; ++i) {
        if (cut[i]) {
            cout << i << endl;
            return 0;
        }
    }

    cout << "No solution" << endl;
    return 0;
}
